@Override
protected PasswordEncoder createStringEncoder() {
    byte[] password = lookupPasswordFromKeyStore();
    char[] chars = it.geosolutions.geostore.core.security.password.SecurityUtils.toChars(password);
    try {
        org.jasypt.encryption.pbe.StandardPBEStringEncryptor stringEncrypter = new org.jasypt.encryption.pbe.StandardPBEStringEncryptor();
        stringEncrypter.setPasswordCharArray(chars);

        if (getProviderName() != null && !getProviderName().isEmpty()) {
            stringEncrypter.setProviderName(getProviderName());
        }
        stringEncrypter.setAlgorithm(getAlgorithm());

        return new org.acegisecurity.providers.encoding.PasswordEncoder() {
            private final org.jasypt.encryption.pbe.StandardPBEStringEncryptor encryptor = stringEncrypter;

            @Override
            public String encodePassword(String rawPass, Object salt) {
                return encryptor.encrypt(rawPass);
            }

            @Override
            public boolean isPasswordValid(String encPass, String rawPass, Object salt) {
                try {
                    String decrypted = encryptor.decrypt(encPass);
                    return decrypted.equals(rawPass);
                } catch (Exception e) {
                    return false;
                }
            }
        };
    } finally {
        it.geosolutions.geostore.core.security.password.SecurityUtils.scramble(password);
        it.geosolutions.geostore.core.security.password.SecurityUtils.scramble(chars);
    }
}

